DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
$var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($var => 'Real');
do {
  ($a, $b) = random_coprime([1..10], [2..10,12]);
  ($c, $d) = random_coprime([1..10], [2..10,12]);
} until ($b != $d);
$A = Fraction($a, $b);
$B = Fraction($c, $d);
$B = random(0,1) ? $B : -$B;
$left = Formula("$var + $A")->reduce;
$right = Formula("$B")->reduce;
($left, $right) = ($left, $right)[NchooseK(2,2)];
Context("FiniteSolutionSets");
Context()->variables->are($var => 'Real');
$solution = $B - $A;
$solset = Formula("{$solution}");

############################################################
# Body
############################################################

BEGIN_PGML
Solve the equation.

[`[$left]=[$right]`]

[_]{$solset}{10}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
